# update_reminder.py — Slack bot that pings Comms Lead every 15 min during P0
import time, requests, os

WEBHOOK = os.environ["SLACK_INCIDENT_WEBHOOK"]
COMMS_LEAD = os.environ.get("COMMS_LEAD_SLACK_ID", "@comms-lead")

def remind_update(incident_title: str, elapsed_min: int):
    requests.post(WEBHOOK, json={
        "text": (
            f":timer_clock: *{COMMS_LEAD}* — {elapsed_min} min have passed since last status page update. "
            f"Post an update for *{incident_title}* now. "
            f"Even 'We are continuing to investigate' is sufficient."
        )
    })

def run_update_cadence(incident_title: str, interval_sec: int = 900):
    elapsed = 0
    while True:
        time.sleep(interval_sec)
        elapsed += interval_sec // 60
        remind_update(incident_title, elapsed)
        # Run until incident is manually stopped
